#!/bin/bash
# Uninstall script for Supremo
# Generated by IntuneBrew

# Exit on error
set -e

echo "Uninstalling Supremo..."

# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping Supremo if running..."
pkill -f "Supremo" 2>/dev/null || true

# Remove /Applications/Supremo.app
echo "Removing /Applications/Supremo.app..."
if [ -d "/Applications/Supremo.app" ]; then
    rm -rf "/Applications/Supremo.app" 2>/dev/null || true
elif [ -f "/Applications/Supremo.app" ]; then
    rm -f "/Applications/Supremo.app" 2>/dev/null || true
fi

# Remove $HOME/Library/Application Support/SupremoRemoteDesktop
echo "Removing $HOME/Library/Application Support/SupremoRemoteDesktop..."
if [ -d "$HOME/Library/Application Support/SupremoRemoteDesktop" ]; then
    rm -rf "$HOME/Library/Application Support/SupremoRemoteDesktop" 2>/dev/null || true
elif [ -f "$HOME/Library/Application Support/SupremoRemoteDesktop" ]; then
    rm -f "$HOME/Library/Application Support/SupremoRemoteDesktop" 2>/dev/null || true
fi

# Remove $HOME/Library/Preferences/Supremo.plist
echo "Removing $HOME/Library/Preferences/Supremo.plist..."
if [ -d "$HOME/Library/Preferences/Supremo.plist" ]; then
    rm -rf "$HOME/Library/Preferences/Supremo.plist" 2>/dev/null || true
elif [ -f "$HOME/Library/Preferences/Supremo.plist" ]; then
    rm -f "$HOME/Library/Preferences/Supremo.plist" 2>/dev/null || true
fi

echo "Uninstallation complete!"
exit 0
